#include<bits/stdc++.h>
using namespace std;
vector<pair<long long,long long>> mp[500050];
long long dis[500050],cnt[500050];
bool vis[500050];
long long n,m;
bool spfa()
{
    memset(dis,0x3f,sizeof(dis));
    dis[0]=0;
    stack<long long> q;
    q.push(0);
    while(!q.empty())
    {
        long long t=q.top();
        q.pop();
        vis[t]=0;
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                cnt[v]++;
                if(cnt[v]>=n)
                {
                    return false;
                }
                dis[v]=dis[t]+val;
                if(!vis[v])
                {
                    vis[v]=1;
                    q.push(v);
                }
            }
        }
    }
    return true;
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        mp[0].push_back(make_pair(i,0));
    }
    for(long long i=1;i<=m;i++)
    {
        long long op,a,b,c;
        scanf("%lld%lld%lld",&op,&a,&b);
        if(op==1)
        {
            scanf("%lld",&c);
            mp[a].push_back(make_pair(b,-c));
        }
        else if(op==2)
        {
            scanf("%lld",&c);
            mp[b].push_back(make_pair(a,c));
        }
        else
        {
            mp[a].push_back(make_pair(b,0));
            mp[b].push_back(make_pair(a,0));
        }
    }
    if(spfa())
    {
        printf("Yes");
    }
    else
    {
        printf("No");
    }
    return 0;
}
